// MARK: - DeviceSecurityManager.swift

import Foundation
import UIKit
import CryptoKit
import LocalAuthentication

final class DeviceSecurityManager: ObservableObject {
    @Published var isDeviceCompromised: Bool = false
    @Published var integrityScore: Int = 0
    @Published var failedChecks: [String] = []
    
    private let requiredIntegrityScore = 5
    private let totalChecks = 8
    
    init() {
        performAllIntegrityChecks()
    }
    
    func performAllIntegrityChecks() {
        var score = 0
        var failed: [String] = []
        
        // Check 1: Jailbreak file paths
        if !checkJailbreakFilePaths() {
            score += 1
        } else {
            failed.append("jailbreak_files_detected")
        }
        
        // Check 2: Suspicious URL schemes
        if !checkSuspiciousURLSchemes() {
            score += 1
        } else {
            failed.append("suspicious_url_schemes")
        }
        
        // Check 3: Writable system paths
        if !checkWritableSystemPaths() {
            score += 1
        } else {
            failed.append("writable_system_paths")
        }
        
        // Check 4: Dynamic library injection
        if !checkDynamicLibraries() {
            score += 1
        } else {
            failed.append("injected_libraries")
        }
        
        // Check 5: Sandbox integrity
        if !checkSandboxIntegrity() {
            score += 1
        } else {
            failed.append("sandbox_compromised")
        }
        
        // Check 6: Debugger detection
        if !checkDebuggerAttached() {
            score += 1
        } else {
            failed.append("debugger_attached")
        }
        
        // Check 7: Suspicious environment variables
        if !checkEnvironmentVariables() {
            score += 1
        } else {
            failed.append("suspicious_environment")
        }
        
        // Check 8: Binary integrity (code signature)
        if !checkBinaryTampering() {
            score += 1
        } else {
            failed.append("binary_tampered")
        }
        
        DispatchQueue.main.async {
            self.integrityScore = score
            self.failedChecks = failed
            // Device is compromised if more than 2 checks fail
            self.isDeviceCompromised = score < self.requiredIntegrityScore
        }
    }
    
    private func checkJailbreakFilePaths() -> Bool {
        let suspiciousPaths = [
            "/Applications/Cydia.app",
            "/Applications/Sileo.app",
            "/Applications/Zebra.app",
            "/Library/MobileSubstrate/MobileSubstrate.dylib",
            "/bin/bash",
            "/usr/sbin/sshd",
            "/etc/apt",
            "/private/var/lib/apt/",
            "/usr/lib/libjailbreak.dylib",
            "/var/lib/dpkg/info",
            "/usr/bin/ssh",
            "/private/var/stash",
            "/private/var/tmp/cydia.log",
            "/Applications/checkra1n.app",
            "/private/var/checkra1n.dmg",
            "/usr/lib/TweakInject",
            "/Library/MobileSubstrate",
            "/var/mobile/Library/Preferences/com.saurik.Cydia.plist"
        ]
        
        for path in suspiciousPaths {
            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        return false
    }
    
    private func checkSuspiciousURLSchemes() -> Bool {
        let suspiciousSchemes = [
            "cydia://",
            "sileo://",
            "zbra://",
            "filza://",
            "undecimus://",
            "activator://"
        ]
        
        for scheme in suspiciousSchemes {
            if let url = URL(string: scheme),
               UIApplication.shared.canOpenURL(url) {
                return true
            }
        }
        return false
    }
    
    private func checkWritableSystemPaths() -> Bool {
        let testPath = "/private/jailbreak_test_\(UUID().uuidString)"
        do {
            try "test".write(toFile: testPath, atomically: true, encoding: .utf8)
            try FileManager.default.removeItem(atPath: testPath)
            return true // Should not be writable
        } catch {
            return false // Expected behavior
        }
    }
    
    private func checkDynamicLibraries() -> Bool {
        let suspiciousLibraries = [
            "SubstrateLoader",
            "SSLKillSwitch",
            "MobileSubstrate",
            "TweakInject",
            "CydiaSubstrate",
            "cynject",
            "libcycript",
            "FridaGadget",
            "frida-agent",
            "libfrida"
        ]
        
        let count = _dyld_image_count()
        for i in 0..<count {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName)
                for lib in suspiciousLibraries {
                    if name.lowercased().contains(lib.lowercased()) {
                        return true
                    }
                }
            }
        }
        return false
    }
    
    private func checkSandboxIntegrity() -> Bool {
        let pid = getpid()
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, pid]
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        if result != 0 {
            return true // Suspicious if sysctl fails unexpectedly
        }
        
        // Check if fork succeeds (shouldn't in sandbox)
        let forkResult = fork()
        if forkResult >= 0 {
            if forkResult > 0 {
                kill(forkResult, SIGTERM)
            }
            return true // Fork should fail in sandbox
        }
        
        return false
    }
    
    private func checkDebuggerAttached() -> Bool {
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        guard result == 0 else { return false }
        
        return (info.kp_proc.p_flag & P_TRACED) != 0
    }
    
    private func checkEnvironmentVariables() -> Bool {
        let suspiciousVars = [
            "DYLD_INSERT_LIBRARIES",
            "_MSSafeMode",
            "DYLD_LIBRARY_PATH",
            "DYLD_FRAMEWORK_PATH"
        ]
        
        for envVar in suspiciousVars {
            if ProcessInfo.processInfo.environment[envVar] != nil {
                return true
            }
        }
        return false
    }
    
    private func checkBinaryTampering() -> Bool {
        guard let bundlePath = Bundle.main.bundlePath as NSString? else { return true }
        let mobileprovisionPath = bundlePath.appendingPathComponent("embedded.mobileprovision")
        
        // In production builds, embedded.mobileprovision should exist
        // For debug/simulator, we skip this check
        #if targetEnvironment(simulator)
        return false
        #else
        if !FileManager.default.fileExists(atPath: mobileprovisionPath) {
            return true
        }
        return false
        #endif
    }
    
    var canPerformSensitiveOperations: Bool {
        return integrityScore >= requiredIntegrityScore && !isDeviceCompromised
    }
    
    func requireBiometricForSensitiveOperation(completion: @escaping (Bool) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false)
            return
        }
        
        context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: "Authenticate to perform this sensitive operation"
        ) { success, _ in
            DispatchQueue.main.async {
                completion(success)
            }
        }
    }
}

// MARK: - SecureKeychain.swift

import Foundation
import Security

enum KeychainError: Error, LocalizedError {
    case duplicateItem
    case itemNotFound
    case unexpectedStatus(OSStatus)
    case encodingError
    case accessControlCreationFailed
    case deviceIntegrityCheckFailed
    
    var errorDescription: String? {
        switch self {
        case .duplicateItem: return "Item already exists in keychain"
        case .itemNotFound: return "Item not found in keychain"
        case .unexpectedStatus(let status): return "Keychain error: \(status)"
        case .encodingError: return "Data encoding error"
        case .accessControlCreationFailed: return "Failed to create access control"
        case .deviceIntegrityCheckFailed: return "Device integrity check failed"
        }
    }
}

final class SecureKeychain {
    
    private static let serviceName = "com.cryptowallet.secure"
    
    static func storePrivateKey(_ keyData: Data, forAccount account: String, securityManager: DeviceSecurityManager) throws {
        // Defense-in-depth: verify device integrity before storing keys
        guard securityManager.canPerformSensitiveOperations else {
            throw KeychainError.deviceIntegrityCheckFailed
        }
        
        // Create access control requiring biometric + device passcode
        var accessControlError: Unmanaged<CFError>?
        guard let accessControl = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            [.biometryCurrentSet, .privateKeyUsage],
            &accessControlError
        ) else {
            throw KeychainError.accessControlCreationFailed
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecValueData as String: keyData,
            kSecAttrAccessControl as String: accessControl,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrSynchronizable as String: false // Never sync private keys
        ]
        
        // Delete existing item first
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeychainError.unexpectedStatus(status)
        }
    }
    
    static func retrievePrivateKey(forAccount account: String, securityManager: DeviceSecurityManager) throws -> Data {
        // Defense-in-depth: verify device integrity before retrieving keys
        guard securityManager.canPerformSensitiveOperations else {
            throw KeychainError.deviceIntegrityCheckFailed
        }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne,
            kSecUseOperationPrompt as String: "Authenticate to access your wallet"
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            if status == errSecItemNotFound {
                throw KeychainError.itemNotFound
            }
            throw KeychainError.unexpectedStatus(status)
        }
        
        return data
    }
    
    static func deletePrivateKey(forAccount account: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unexpectedStatus(status)
        }
    }
    
    static func hasStoredKey(forAccount account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: account,
            kSecReturnData as String: false
        ]
        
        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }
}

