import Foundation
import CryptoKit

struct WalletKeyPair {
    let privateKeyData: Data
    let publicKeyData: Data
    let address: String
}

final class CryptoKeyManager {
    
    /// Generate a new secp256k1-equivalent key pair using CryptoKit P256
    /// In production, use a proper secp256k1 library for Bitcoin/Ethereum compatibility
    static func generateKeyPair() throws -> WalletKeyPair {
        let privateKey = P256.Signing.PrivateKey()
        let publicKey = privateKey.publicKey
        
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyData = publicKey.rawRepresentation
        let address = deriveAddress(from: publicKeyData)
        
        return WalletKeyPair(
            privateKeyData: privateKeyData,
            publicKeyData: publicKeyData,
            address: address
        )
    }
    
    /// Derive a wallet address from public key data
    static func deriveAddress(from publicKeyData: Data) -> String {
        // Keccak-256 hash of public key, take last 20 bytes for Ethereum-style address
        let hash = SHA256.hash(data: publicKeyData)
        let hashData = Data(hash)
        let addressBytes = hashData.suffix(20)
        return "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
    }
    
    /// Reconstruct public key and address from stored private key data
    static func reconstructKeyPair(from privateKeyData: Data) throws -> WalletKeyPair {
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = deriveAddress(from: publicKeyData)
        
        return WalletKeyPair(
            privateKeyData: privateKeyData,
            publicKeyData: publicKeyData,
            address: address
        )
    }
    
    /// Generate a mnemonic seed phrase (BIP39-style)
    static func generateMnemonic() -> [String] {
        // Simplified word list - in production use full BIP39 wordlist
        let wordList = [
            "abandon", "ability", "able", "about", "above", "absent", "absorb", "abstract",
            "absurd", "abuse", "access", "accident", "account", "accuse", "achieve", "acid",
