            "bachelor", "bacon", "badge", "bag", "balance", "balcony", "ball", "bamboo",
            "banana", "banner", "bar", "barely", "bargain", "barrel", "base", "basic",
            "basket", "battle", "beach", "bean", "beauty", "because", "become", "beef",
            "before", "begin", "behave", "behind", "believe", "below", "belt", "bench",
            "benefit", "best", "betray", "better", "between", "beyond", "bicycle", "bid",
            "bike", "bind", "biology", "bird", "birth", "bitter", "black", "blade",
            "blame", "blanket", "blast", "bleak", "bless", "blind", "blood", "blossom",
            "blow", "blue", "blur", "blush", "board", "boat", "body", "boil",
            "bomb", "bone", "bonus", "book", "boost", "border", "boring", "borrow",
            "boss", "bottom", "bounce", "box", "boy", "bracket", "brain", "brand",
            "brass", "brave", "bread", "breeze", "brick", "bridge", "brief", "bright",
            "bring", "brisk", "broccoli", "broken", "bronze", "broom", "brother", "brown",
            "brush", "bubble", "buddy", "budget", "buffalo", "build", "bulb", "bulk",
            "bullet", "bundle", "bunny", "burden", "burger", "burst", "bus", "business",
            "busy", "butter", "buyer", "buzz", "cabbage", "cabin", "cable", "cactus"
        ]
        
        var mnemonic: [String] = []
        for _ in 0..<12 {
            var randomBytes = [UInt8](repeating: 0, count: 4)
            _ = SecRandomCopyBytes(kSecRandomDefault, randomBytes.count, &randomBytes)
            let index = Int(Data(randomBytes).withUnsafeBytes { $0.load(as: UInt32.self) }) % wordList.count
            mnemonic.append(wordList[abs(index)])
        }
        
        return mnemonic
    }
    
    /// Derive a private key from mnemonic (simplified - use proper BIP39/BIP32 in production)
    static func deriveKeyFromMnemonic(_ mnemonic: [String]) throws -> Data {
        let mnemonicString = mnemonic.joined(separator: " ")
        let mnemonicData = Data(mnemonicString.utf8)
        let salt = Data("mnemonic".utf8)
        
        // Use HKDF as a simplified key derivation
        let inputKey = SymmetricKey(data: mnemonicData)
        let derivedKey = HKDF<SHA256>.deriveKey(
            inputKeyMaterial: inputKey,
            salt: salt,
            info: Data("wallet-key-derivation".utf8),
            outputByteCount: 32
        )
        
        return derivedKey.withUnsafeBytes { Data($0) }
    }
}

// MARK: - TransactionSigner.swift

import Foundation
import CryptoKit

struct Transaction: Codable, Identifiable {
    let id: String
    let from: String
    let to: String
    let amount: String
    let gasPrice: String
    let gasLimit: String
    let nonce: Int
    let chainId: Int
    let timestamp: Date
    var signature: String?
    var txHash: String?
    var status: TransactionStatus
    
    enum TransactionStatus: String, Codable {
        case pending
        case signed
        case submitted
        case confirmed
        case failed
    }
    
    init(from: String, to: String, amount: String, gasPrice: String = "20", gasLimit: String = "21000", nonce: Int = 0, chainId: Int = 1) {
        self.id = UUID().uuidString
        self.from = from
        self.to = to
        self.amount = amount
        self.gasPrice = gasPrice
        self.gasLimit = gasLimit
        self.nonce = nonce
        self.chainId = chainId
        self.timestamp = Date()
        self.signature = nil
        self.txHash = nil
        self.status = .pending
    }
}

final class TransactionSigner {
    
    /// Sign a transaction with the private key
    static func signTransaction(_ transaction: Transaction, privateKeyData: Data, securityManager: DeviceSecurityManager) throws -> Transaction {
        // Defense-in-depth: verify device integrity before signing
        guard securityManager.canPerformSensitiveOperations else {
            throw TransactionError.deviceIntegrityCheckFailed
        }
        
        // Serialize transaction for signing
        let txData = try serializeTransaction(transaction)
        
        // Hash the transaction data
        let txHash = SHA256.hash(data: txData)
        let txHashData = Data(txHash)
        
        // Sign with private key
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: txHashData)
        
        var signedTx = transaction
        signedTx.signature = signature.rawRepresentation.base64EncodedString()
        signedTx.txHash = txHashData.map { String(format: "%02x", $0) }.joined()
        signedTx.status = .signed
        
        return signedTx
    }
    
    /// Verify a transaction signature
    static func verifySignature(_ transaction: Transaction, publicKeyData: Data) throws -> Bool {
        guard let signatureBase64 = transaction.signature else {
            throw TransactionError.missingSignature
        }
        
        guard let signatureData = Data(base64Encoded: signatureBase64) else {
            throw TransactionError.invalidSignature
        }
        
        let txData = try serializeTransaction(transaction)
        let txHash = SHA256.hash(data: txData)
        let txHashData = Data(txHash)
        
        let publicKey = try P256.Signing.PublicKey(rawRepresentation: publicKeyData)
        let signature = try P256.Signing.ECDSASignature(rawRepresentation: signatureData)
        
        return publicKey.isValidSignature(signature, for: txHashData)
    }
    
    private static func serializeTransaction(_ transaction: Transaction) throws -> Data {
        // RLP-like encoding (simplified)
        let txFields: [String: Any] = [
            "from": transaction.from,
            "to": transaction.to,
            "amount": transaction.amount,
            "gasPrice": transaction.gasPrice,
            "gasLimit": transaction.gasLimit,
            "nonce": transaction.nonce,
            "chainId": transaction.chainId
        ]
        
        return try JSONSerialization.data(withJSONObject: txFields, options: .sortedKeys)
    }
}

enum TransactionError: Error, LocalizedError {
    case deviceIntegrityCheckFailed
    case missingSignature
    case invalidSignature
    case serializationFailed
    case signingFailed
    case networkError(String)
    case insufficientFunds
    case invalidAddress
    
    var errorDescription: String? {
        switch self {
        case .deviceIntegrityCheckFailed: return "Device integrity check failed. Cannot sign transactions on compromised devices."
        case .missingSignature: return "Transaction is not signed"
        case .invalidSignature: return "Invalid transaction signature"
        case .serializationFailed: return "Failed to serialize transaction"
        case .signingFailed: return "Failed to sign transaction"
        case .networkError(let msg): return "Network error: \(msg)"
        case .insufficientFunds: return "Insufficient funds"
        case .invalidAddress: return "Invalid wallet address"
        }
    }
}

// MARK: - BlockchainService.swift

import Foundation

struct BlockchainBalance: Codable {
    let address: String
    let balance: String
    let currency: String
}

struct BlockchainTransactionReceipt: Codable {
    let txHash: String
    let blockNumber: Int?
    let status: String
    let gasUsed: String?
}

final class BlockchainService: ObservableObject {
    @Published var isConnected: Bool = false
    @Published var currentBlockNumber: Int = 0
    @Published var networkName: String = "Ethereum Mainnet"
    
    private let rpcURL: URL
    private let session: URLSession
    private var requestId: Int = 0
    
    init(rpcEndpoint: String = "https://eth-mainnet.g.alchemy.com/v2/demo") {
        self.rpcURL = URL(string: rpcEndpoint)!
        
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        self.session = URLSession(configuration: config)
    }
    
    private func nextRequestId() -> Int {
        requestId += 1
        return requestId
    }
    
    func getBalance(address: String) async throws -> BlockchainBalance {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getBalance",
            "params": [address, "latest"],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw TransactionError.networkError("Invalid balance response")
        }
        
        // Convert hex wei to ETH string
        let balanceInEth = hexWeiToEth(result)
        
        return BlockchainBalance(
            address: address,
            balance: balanceInEth,
            currency: "ETH"
        )
    }
    
    func getTransactionCount(address: String) async throws -> Int {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionCount",
            "params": [address, "latest"],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw TransactionError.networkError("Invalid nonce response")
        }
        
        return hexToInt(result)
    }
    
    func sendSignedTransaction(_ signedTx: Transaction) async throws -> BlockchainTransactionReceipt {
        guard let signature = signedTx.signature, let txHash = signedTx.txHash else {
            throw TransactionError.missingSignature
        }
        
        // In production, this would send the raw signed transaction bytes
        let rawTx = "0x" + (signature + txHash)
        
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [rawTx],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        if let error = response["error"] as? [String: Any],
           let message = error["message"] as? String {
            throw TransactionError.networkError(message)
        }
        
        let resultHash = response["result"] as? String ?? txHash
        
        return BlockchainTransactionReceipt(
            txHash: resultHash,
            blockNumber: nil,
            status: "pending",
            gasUsed: nil
        )
    }
    
    func getTransactionReceipt(txHash: String) async throws -> BlockchainTransactionReceipt {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionReceipt",
            "params": [txHash],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        if let result = response["result"] as? [String: Any] {
            let blockNumber = result["blockNumber"] as? String
            let status = result["status"] as? String
            let gasUsed = result["gasUsed"] as? String
            
            return BlockchainTransactionReceipt(
                txHash: txHash,
                blockNumber: blockNumber.map { hexToInt($0) },
                status: status == "0x1" ? "confirmed" : "failed",
                gasUsed: gasUsed
            )
        }
        
        return BlockchainTransactionReceipt(
            txHash: txHash,
            blockNumber: nil,
            status: "pending",
            gasUsed: nil
        )
    }
    
    func getCurrentBlockNumber() async throws -> Int {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_blockNumber",
            "params": [],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw TransactionError.networkError("Invalid block number response")
        }
        
        let blockNumber = hexToInt(result)
        DispatchQueue.main.async {
            self.currentBlockNumber = blockNumber
            self.isConnected = true
        }
        return blockNumber
    }
    
    func getGasPrice() async throws -> String {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_gasPrice",
            "params": [],
            "id": nextRequestId()
        ]
        
        let response = try await makeRPCCall(params: params)
        
        guard let result = response["result"] as? String else {
            throw TransactionError.networkError("Invalid gas price response")
        }
        
        return result
    }
    
    private func makeRPCCall(params: [String: Any]) async throws -> [String: Any] {
        var request = URLRequest(url: rpcURL)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 30
        request.httpBody = try JSONSerialization.data(withJSONObject: params)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw TransactionError.networkError("HTTP error")
        }
        
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            throw TransactionError.networkError("Invalid JSON response")
        }
        
        return json
    }
    
    private func hexWeiToEth(_ hex: String) -> String {
        let cleanHex = hex.hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        guard let weiValue = UInt64(cleanHex, radix: 16) else { return "0.0" }
        let ethValue = Double(weiValue) / 1_000_000_000_000_000_000.0
        return String(format: "%.6f", ethValue)
    }
    
    private func hexToInt(_ hex: String) -> Int {
        let cleanHex = hex.hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        return Int(cleanHex, radix: 16) ?? 0
    }
}

// MARK: - WalletManager.swift

import Foundation
import SwiftUI

struct WalletAccount: Identifiable, Codable {
    let id: String
    let address: String
    let name: String
    let createdAt: Date
    var balance: String?
    
    init(address: String, name: String) {
        self.id = UUID().uuidString
        self.address = address
        self.name = name
        self.createdAt = Date()
        self.balance = nil
    }
}

final class WalletManager: ObservableObject {
    @Published var accounts: [WalletAccount] = []
    @Published var selectedAccount: WalletAccount?
    @Published var transactions: [Transaction] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var mnemonic: [String]?
    
    let blockchainService = BlockchainService()
    
    private let accountsKey = "wallet_accounts"
    private let transactionsKey = "wallet_transactions"
    
    init() {
        loadAccounts()
        loadTransactions()
    }
    
    func createNewWallet(name: String, securityManager: DeviceSecurityManager) async throws -> WalletAccount {
        guard securityManager.canPerformSensitiveOperations else {
            throw TransactionError.deviceIntegrityCheckFailed
        }
        
        // Generate mnemonic
        let words = CryptoKeyManager.generateMnemonic()
        
        // Generate key pair
        let keyPair = try CryptoKeyManager.generateKeyPair()
        
        // Store private key securely in keychain
        try SecureKeychain.storePrivateKey(
            keyPair.privateKeyData,
            forAccount: keyPair.address,
            securityManager: securityManager
        )
        
        let account = WalletAccount(address: keyPair.address, name: name)
        
        DispatchQueue.main.async {
            self.accounts.append(account)
            self.selectedAccount = account
            self.mnemonic = words
            self.saveAccounts()
        }
        
        return account
    }
    
    func importWallet(mnemonic: [String], name: String, securityManager: DeviceSecurityManager) async throws -> WalletAccount {
        guard securityManager.canPerformSensitiveOperations else {
            throw TransactionError.deviceIntegrityCheckFailed
        }
        
        // Derive key from mnemonic
        let derivedKeyData = try CryptoKeyManager.deriveKeyFromMnemonic(mnemonic)
        
        // Generate address from derived key
        let address = CryptoKeyManager.deriveAddress(from: derivedKeyData)
        
        // Store in keychain
        try SecureKeychain.storePrivateKey(
            derivedKeyData,
            forAccount: address,
            securityManager: securityManager
        )
        
        let account = WalletAccount(address: address, name: name)
        
        DispatchQueue.main.async {
            self.accounts.append(account)
            self.selectedAccount = account
            self.saveAccounts()
        }
        
        return account
    }
    
    func sendTransaction(to: String, amount: String, securityManager: DeviceSecurityManager) async throws -> Transaction {
        guard securityManager.canPerformSensitiveOperations else {
            throw TransactionError.deviceIntegrityCheckFailed
        }
        
        guard let account = selectedAccount else {
            throw TransactionError.networkError("No account selected")
        }
        
        // Validate address
        guard isValidAddress(to) else {
            throw TransactionError.invalidAddress
        }
        
        DispatchQueue.main.async {
            self.isLoading = true
        }
        
        defer {
            DispatchQueue.main.async {
                self.isLoading = false
            }
        }
        
        // Get nonce
        let nonce = try await blockchainService.getTransactionCount(address: account.address)
        
        // Create transaction
        var transaction = Transaction(
            from: account.address,
            to: to,
            amount: amount,
            nonce: nonce
        )
        
        // Retrieve private key (requires biometric auth via keychain)
        let privateKeyData = try SecureKeychain.retrievePrivateKey(
            forAccount: account.address,
            securityManager: securityManager
        )
        
        // Sign transaction
        transaction = try TransactionSigner.signTransaction(
            transaction,
            privateKeyData: privateKeyData,
            securityManager: securityManager
        )
        
        // Clear private key from memory
        // (In production, use a secure memory allocator)
        
        // Submit to blockchain
        let receipt = try await blockchainService.sendSignedTransaction(transaction)
        transaction.txHash = receipt.txHash
        transaction.status = .submitted
        
        DispatchQueue.main.async {
            self.transactions.insert(transaction, at: 0)
            self.saveTransactions()
        }
        
        return transaction
    }
    
    func refreshBalance(securityManager: DeviceSecurityManager) async {
        guard let account = selectedAccount else { return }
        
        do {
            let balance = try await blockchainService.getBalance(address: account.address)
            DispatchQueue.main.async {
                if let index = self.accounts.firstIndex(where: { $0.id == account.id }) {
                    self.accounts[index].balance = balance.balance
                    self.selectedAccount = self.accounts[index]
                    self.saveAccounts()
                }
            }
        } catch {
            DispatchQueue.main.async {
                self.errorMessage = error.localizedDescription
            }
        }
    }
    
    func deleteAccount(_ account: WalletAccount) throws {
        try SecureKeychain.deletePrivateKey(forAccount: account.address)
        accounts.removeAll { $0.id == account.id }
        if selectedAccount?.id == account.id {
            selectedAccount = accounts.first
        }
        saveAccounts()
    }
    
    private func isValidAddress(_ address: String) -> Bool {
        let pattern = "^0x[0-9a-fA-F]{40}$"
        return address.range(of: pattern, options: .regularExpression) != nil
    }
    
    private func saveAccounts() {
        if let data = try? JSONEncoder().encode(accounts) {
            UserDefaults.standard.set(data, forKey: accountsKey)
        }
    }
    
    private func loadAccounts() {
        if let data = UserDefaults.standard.data(forKey: accountsKey),
           let decoded = try? JSONDecoder().decode([WalletAccount].self, from: data) {
            accounts = decoded
            selectedAccount = accounts.first
        }
    }
    
    private func saveTransactions() {
        if let data = try? JSONEncoder().encode(transactions) {
            UserDefaults.standard.set(data, forKey: transactionsKey)
        }
    }
    
    private func loadTransactions() {
        if let data = UserDefaults.standard.data(forKey: transactionsKey),
           let decoded = try? JSONDecoder().decode([Transaction].self, from: data) {
            transactions = decoded
        }
    }
}

// MARK: - SecurityWarningView.swift

import SwiftUI

struct SecurityWarningView: View {
    @ObservedObject var securityManager: DeviceSecurityManager
    @State private var showDetails = false
    
    var body: some View {
        VStack(spacing: 24) {
            Spacer()
            
            Image(systemName: "exclamationmark.shield.fill")
                .font(.system(size: 80))
                .foregroundColor(.red)
            
            Text("Security Alert")
                .font(.largeTitle)
                .fontWeight(.bold)
                .foregroundColor(.red)
            
            Text("Your device has failed integrity checks. For the safety of your funds, wallet operations are restricted on compromised devices.")
                .font(.body)
                .multilineTextAlignment(.center)
                .padding(.horizontal, 32)
                .foregroundColor(.secondary)
            
            VStack(alignment: .leading, spacing: 8) {
                Text("Failed Checks:")
                    .font(.headline)
                    .foregroundColor(.red)
                
                ForEach(securityManager.failedChecks, id: \.self) { check in
                    HStack {
                        Image(systemName: "xmark.circle.fill")
                            .foregroundColor(.red)
                        Text(check.replacingOccurrences(of: "_", with: " ").capitalized)
                            .font(.caption)
                    }
                }
            }
            .padding()
            .background(Color.red.opacity(0.1))
            .cornerRadius(12)
            .padding(.horizontal, 32)
            
            Text("Integrity Score: \(securityManager.integrityScore)/8")
                .font(.caption)
                .foregroundColor(.secondary)
            
            Button("Re-check Device") {
                securityManager.performAllIntegrityChecks()
            }
            .buttonStyle(.borderedProminent)
            .tint(.red)
            
            Spacer()
            
            Text("If you believe this is an error, please ensure your device is running unmodified iOS.")
                .font(.caption2)
                .multilineTextAlignment(.center)
                .foregroundColor(.secondary)
                .padding(.horizontal, 32)
                .padding(.bottom, 16)
        }
    }
}

