    @State private var showImportWallet = false
    @State private var showSendTransaction = false
    @State private var showMnemonic = false
    
    var body: some View {
        NavigationView {
            VStack(spacing: 0) {
                if walletManager.accounts.isEmpty {
                    emptyStateView
                } else {
                    walletContentView
                }
            }
            .navigationTitle("Crypto Wallet")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Menu {
                        Button(action: { showCreateWallet = true }) {
                            Label("Create New Wallet", systemImage: "plus.circle")
                        }
                        Button(action: { showImportWallet = true }) {
                            Label("Import Wallet", systemImage: "square.and.arrow.down")
                        }
                    } label: {
                        Image(systemName: "ellipsis.circle")
                    }
                }
                
                ToolbarItem(placement: .navigationBarLeading) {
                    securityBadge
                }
            }
            .sheet(isPresented: $showCreateWallet) {
                CreateWalletView()
                    .environmentObject(walletManager)
                    .environmentObject(securityManager)
            }
            .sheet(isPresented: $showImportWallet) {
                ImportWalletView()
                    .environmentObject(walletManager)
                    .environmentObject(securityManager)
            }
            .sheet(isPresented: $showSendTransaction) {
                SendTransactionView()
                    .environmentObject(walletManager)
                    .environmentObject(securityManager)
            }
            .sheet(isPresented: $showMnemonic) {
                MnemonicDisplayView(mnemonic: walletManager.mnemonic ?? [])
            }
        }
    }
    
    private var securityBadge: some View {
        HStack(spacing: 4) {
            Image(systemName: securityManager.canPerformSensitiveOperations ? "checkmark.shield.fill" : "exclamationmark.shield.fill")
                .foregroundColor(securityManager.canPerformSensitiveOperations ? .green : .orange)
            Text("\(securityManager.integrityScore)/8")
                .font(.caption2)
                .foregroundColor(.secondary)
        }
    }
    
    private var emptyStateView: some View {
        VStack(spacing: 24) {
            Spacer()
            
            Image(systemName: "wallet.pass")
                .font(.system(size: 60))
                .foregroundColor(.blue)
            
            Text("Welcome to Crypto Wallet")
                .font(.title2)
                .fontWeight(.bold)
            
            Text("Create a new wallet or import an existing one to get started.")
                .font(.body)
                .foregroundColor(.secondary)
                .multilineTextAlignment(.center)
                .padding(.horizontal, 40)
            
            VStack(spacing: 12) {
                Button(action: { showCreateWallet = true }) {
                    HStack {
                        Image(systemName: "plus.circle.fill")
                        Text("Create New Wallet")
                    }
                    .frame(maxWidth: .infinity)
                    .padding()
                    .background(Color.blue)
                    .foregroundColor(.white)
                    .cornerRadius(12)
                }
                
                Button(action: { showImportWallet = true }) {
                    HStack {
                        Image(systemName: "square.and.arrow.down")
                        Text("Import Wallet")
                    }
                    .frame(maxWidth: .infinity)
                    .padding()
                    .background(Color.blue.opacity(0.1))
                    .foregroundColor(.blue)
                    .cornerRadius(12)
                }
            }
            .padding(.horizontal, 32)
            
            Spacer()
        }
    }
    
    private var walletContentView: some View {
        ScrollView {
            VStack(spacing: 20) {
                // Account Card
                if let account = walletManager.selectedAccount {
                    AccountCardView(account: account)
                        .onAppear {
                            Task {
                                await walletManager.refreshBalance(securityManager: securityManager)
                            }
                        }
                }
                
                // Account Picker
                if walletManager.accounts.count > 1 {
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 8) {
                            ForEach(walletManager.accounts) { account in
                                Button(action: {
                                    walletManager.selectedAccount = account
                                }) {
                                    Text(account.name)
                                        .font(.caption)
                                        .padding(.horizontal, 12)
                                        .padding(.vertical, 6)
                                        .background(
                                            walletManager.selectedAccount?.id == account.id
                                            ? Color.blue : Color.gray.opacity(0.2)
                                        )
                                        .foregroundColor(
                                            walletManager.selectedAccount?.id == account.id
                                            ? .white : .primary
                                        )
                                        .cornerRadius(20)
                                }
                            }
                        }
                        .padding(.horizontal)
                    }
                }
                
                // Action Buttons
                HStack(spacing: 16) {
                    ActionButton(title: "Send", icon: "arrow.up.circle.fill", color: .blue) {
                        showSendTransaction = true
                    }
                    
                    ActionButton(title: "Receive", icon: "arrow.down.circle.fill", color: .green) {
                        // Show receive address
                    }
                    
                    ActionButton(title: "Refresh", icon: "arrow.clockwise.circle.fill", color: .orange) {
                        Task {
                            await walletManager.refreshBalance(securityManager: securityManager)
                        }
                    }
                }
                .padding(.horizontal)
                
                // Transaction History
                VStack(alignment: .leading, spacing: 12) {
                    Text("Recent Transactions")
                        .font(.headline)
                        .padding(.horizontal)
                    
                    if walletManager.transactions.isEmpty {
                        Text("No transactions yet")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 40)
                    } else {
                        ForEach(walletManager.transactions) { tx in
                            TransactionRowView(transaction: tx)
                        }
                    }
                }
                
                // Show mnemonic button if available
                if walletManager.mnemonic != nil {
                    Button(action: { showMnemonic = true }) {
                        HStack {
                            Image(systemName: "key.fill")
                            Text("View Recovery Phrase")
                        }
                        .font(.caption)
                        .foregroundColor(.orange)
                    }
                    .padding(.top, 8)
                }
            }
            .padding(.vertical)
        }
        .refreshable {
            await walletManager.refreshBalance(securityManager: securityManager)
        }
    }
}

