// MARK: - TransactionRowView.swift

struct TransactionRowView: View {
    let transaction: Transaction
    
    var body: some View {
        HStack(spacing: 12) {
            Image(systemName: statusIcon)
                .font(.title3)
                .foregroundColor(statusColor)
                .frame(width: 40, height: 40)
                .background(statusColor.opacity(0.1))
                .cornerRadius(20)
            
            VStack(alignment: .leading, spacing: 4) {
                Text("To: \(truncatedAddress(transaction.to))")
                    .font(.subheadline)
                    .fontWeight(.medium)
                
                Text(transaction.status.rawValue.capitalized)
                    .font(.caption)
                    .foregroundColor(statusColor)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text("-\(transaction.amount) ETH")
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .foregroundColor(.red)
                
                Text(formattedDate)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
        }
        .padding(.horizontal)
        .padding(.vertical, 8)
    }
    
    private var statusIcon: String {
        switch transaction.status {
        case .pending: return "clock"
        case .signed: return "signature"
        case .submitted: return "paperplane"
        case .confirmed: return "checkmark.circle"
        case .failed: return "xmark.circle"
        }
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .pending: return .orange
        case .signed: return .blue
        case .submitted: return .purple
        case .confirmed: return .green
        case .failed: return .red
        }
    }
    
    private var formattedDate: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: transaction.timestamp)
    }
    
    private func truncatedAddress(_ address: String) -> String {
        if address.count > 12 {
            return String(address.prefix(8)) + "..." + String(address.suffix(4))
        }
        return address
    }
}

// MARK: - CreateWalletView.swift

struct CreateWalletView: View {
    @EnvironmentObject var walletManager: WalletManager
    @EnvironmentObject var securityManager: DeviceSecurityManager
    @Environment(\.dismiss) var dismiss
    
    @State private var walletName = ""
    @State private var isCreating = false
    @State private var errorMessage: String?
    @State private var createdMnemonic: [String]?
    @State private var showMnemonic = false
    
    var body: some View {
        NavigationView {
            VStack(spacing: 24) {
                if let mnemonic = createdMnemonic {
                    mnemonicView(mnemonic)
                } else {
                    createFormView
                }
            }
            .navigationTitle("Create Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private var createFormView: some View {
        VStack(spacing: 24) {
            Image(systemName: "wallet.pass.fill")
                .font(.system(size: 50))
                .foregroundColor(.blue)
                .padding(.top, 40)
            
            Text("Create a new wallet")
                .font(.title2)
                .fontWeight(.bold)
            
            TextField("Wallet Name", text: $walletName)
                .textFieldStyle(.roundedBorder)
                .padding(.horizontal, 32)
            
            if !securityManager.canPerformSensitiveOperations {
                HStack {
                    Image(systemName: "exclamationmark.triangle.fill")
                        .foregroundColor(.orange)
                    Text("Device integrity checks did not fully pass. Wallet creation may be restricted.")
                        .font(.caption)
                        .foregroundColor(.orange)
                }
                .padding(.horizontal, 32)
            }
            
            if let error = errorMessage {
                Text(error)
                    .font(.caption)
                    .foregroundColor(.red)
                    .padding(.horizontal, 32)
            }
            
            Button(action: createWallet) {
                HStack {
                    if isCreating {
                        ProgressView()
                            .tint(.white)
                    }
                    Text(isCreating ? "Creating..." : "Create Wallet")
                }
                .frame(maxWidth: .infinity)
                .padding()
                .background(walletName.isEmpty ? Color.gray : Color.blue)
                .foregroundColor(.white)
                .cornerRadius(12)
            }
            .disabled(walletName.isEmpty || isCreating)
            .padding(.horizontal, 32)
            
            Spacer()
        }
    }
    
    private func mnemonicView(_ mnemonic: [String]) -> some View {
        VStack(spacing: 16) {
            Image(systemName: "exclamationmark.triangle.fill")
                .font(.system(size: 40))
                .foregroundColor(.orange)
                .padding(.top, 20)
            
            Text("Recovery Phrase")
                .font(.title2)
                .fontWeight(.bold)
            
            Text("Write down these 12 words in order. This is the ONLY way to recover your wallet. Never share this with anyone.")
                .font(.caption)
                .foregroundColor(.red)
                .multilineTextAlignment(.center)
                .padding(.horizontal, 32)
            
            LazyVGrid(columns: [
                GridItem(.flexible()),
                GridItem(.flexible()),
                GridItem(.flexible())
            ], spacing: 8) {
                ForEach(Array(mnemonic.enumerated()), id: \.offset) { index, word in
                    HStack(spacing: 4) {
                        Text("\(index + 1).")
                            .font(.caption2)
                            .foregroundColor(.secondary)
                        Text(word)
                            .font(.caption)
                            .fontWeight(.medium)
                    }
                    .padding(.horizontal, 8)
                    .padding(.vertical, 6)
                    .background(Color.orange.opacity(0.1))
                    .cornerRadius(8)
                }
            }
            .padding(.horizontal, 16)
            
            Button("I've Saved My Recovery Phrase") {
                dismiss()
            }
            .frame(maxWidth: .infinity)
            .padding()
            .background(Color.green)
            .foregroundColor(.white)
            .cornerRadius(12)
            .padding(.horizontal, 32)
            .padding(.top, 16)
            
            Spacer()
        }
    }
    
    private func createWallet() {
        isCreating = true
        errorMessage = nil
        
        Task {
            do {
                let _ = try await walletManager.createNewWallet(
                    name: walletName,
                    securityManager: securityManager
                )
                
                DispatchQueue.main.async {
                    self.isCreating = false
                    self.createdMnemonic = walletManager.mnemonic
                }
            } catch {
                DispatchQueue.main.async {
                    self.isCreating = false
                    self.errorMessage = error.localizedDescription
                }
            }
        }
    }
}

